-- =============================================================================
-- SEÇÃO 2 — ALTERAÇÕES EM TABELAS EXISTENTES (executar nesta ordem)
-- =============================================================================

-- -----------------------------------------------------------------------------
-- 2.1 infotime_plano_conta — colunas de classificação contábil
--     Sprint 1 — necessário para DRE, DFC e Balanço
-- -----------------------------------------------------------------------------
ALTER TABLE public.infotime_plano_conta
    ADD COLUMN IF NOT EXISTS natureza_dre   varchar(30) DEFAULT NULL,
    ADD COLUMN IF NOT EXISTS natureza_dfc   varchar(30) DEFAULT NULL,
    ADD COLUMN IF NOT EXISTS grupo_contabil varchar(30) DEFAULT NULL,
    ADD COLUMN IF NOT EXISTS classificador  varchar(20) DEFAULT NULL;

COMMENT ON COLUMN public.infotime_plano_conta.natureza_dre IS
    'Classificação DRE: RECEITA_BRUTA | DEDUCAO | CUSTO_VARIAVEL | CUSTO_FIXO | DESPESA_FINANCEIRA | OUTRAS_RECEITAS | NAO_APLICAVEL';
COMMENT ON COLUMN public.infotime_plano_conta.natureza_dfc IS
    'Classificação DFC: OPERACIONAL | INVESTIMENTO | FINANCIAMENTO | NAO_CAIXA';
COMMENT ON COLUMN public.infotime_plano_conta.grupo_contabil IS
    'Grupo do balanço: ATIVO_CIRCULANTE | ATIVO_NAO_CIRCULANTE | ATIVO_IMOBILIZADO | ATIVO_INTANGIVEL | PASSIVO_CIRCULANTE | PASSIVO_NAO_CIRCULANTE | CAPITAL_SOCIAL | RESERVAS | LUCROS_ACUMULADOS | RESULTADO_EXERCICIO';
COMMENT ON COLUMN public.infotime_plano_conta.classificador IS
    'Classificador contábil hierárquico ex: 1.1.01, 2.2.03';

CREATE INDEX IF NOT EXISTS idx_infotime_plano_conta_natureza_dre
    ON public.infotime_plano_conta USING btree (natureza_dre)
    WHERE natureza_dre IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_infotime_plano_conta_natureza_dfc
    ON public.infotime_plano_conta USING btree (natureza_dfc)
    WHERE natureza_dfc IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_infotime_plano_conta_grupo_contabil
    ON public.infotime_plano_conta USING btree (grupo_contabil)
    WHERE grupo_contabil IS NOT NULL;

-- -----------------------------------------------------------------------------
-- 2.2 infotime_conta_caixa — flag de composição do DFC
--     Sprint 7 — necessário para DFC
-- -----------------------------------------------------------------------------
ALTER TABLE public.infotime_conta_caixa
    ADD COLUMN IF NOT EXISTS compoe_saldo_dfc bpchar(1) NOT NULL DEFAULT 'S';

COMMENT ON COLUMN public.infotime_conta_caixa.compoe_saldo_dfc IS
    '''S'' = conta bancária/caixa que compõe o saldo inicial/final do DFC. ''N'' = conta de controle interno.';

-- -----------------------------------------------------------------------------
-- 2.3 infotime_cliente — score de inadimplência desnormalizado
--     Sprint 4 — necessário para Score de inadimplência
-- -----------------------------------------------------------------------------
ALTER TABLE public.infotime_cliente
    ADD COLUMN IF NOT EXISTS score_inadimplencia numeric(5,2) DEFAULT NULL,
    ADD COLUMN IF NOT EXISTS classificacao_score  varchar(10)  DEFAULT NULL;

COMMENT ON COLUMN public.infotime_cliente.score_inadimplencia IS
    'Score calculado semanalmente: 0 (alto risco) a 100 (bom pagador)';
COMMENT ON COLUMN public.infotime_cliente.classificacao_score IS
    'VERDE (80-100) | AMARELO (50-79) | VERMELHO (0-49)';

CREATE INDEX IF NOT EXISTS idx_infotime_cliente_score_inadimplencia
    ON public.infotime_cliente USING btree (score_inadimplencia)
    WHERE score_inadimplencia IS NOT NULL;

-- -----------------------------------------------------------------------------
-- 2.4 Indexes de performance em tabelas de lançamento
--     Sprint 1 — melhora queries de aging, DRE e cockpit
-- -----------------------------------------------------------------------------
CREATE INDEX IF NOT EXISTS idx_infotime_lancamento_receita_tenant_data_prev
    ON public.infotime_lancamento_receita USING btree (id_tenacidade, data_previsao)
    WHERE id_situacao_documento NOT IN (4, 24);

CREATE INDEX IF NOT EXISTS idx_infotime_lancamento_receita_tenant_competencia
    ON public.infotime_lancamento_receita USING btree (id_tenacidade, data_competencia);

CREATE INDEX IF NOT EXISTS idx_infotime_lancamento_receita_plano_conta
    ON public.infotime_lancamento_receita USING btree (id_plano_conta);

CREATE INDEX IF NOT EXISTS idx_infotime_lancamento_despesa_tenant_data_prev
    ON public.infotime_lancamento_despesa USING btree (id_tenacidade, data_previsao)
    WHERE id_situacao_documento NOT IN (4);

CREATE INDEX IF NOT EXISTS idx_infotime_lancamento_despesa_tenant_competencia
    ON public.infotime_lancamento_despesa USING btree (id_tenacidade, data_competencia);

CREATE INDEX IF NOT EXISTS idx_infotime_lancamento_despesa_plano_conta
    ON public.infotime_lancamento_despesa USING btree (id_plano_conta);


-- =============================================================================
-- SEÇÃO 3 — TIER 1: TABELAS NOVAS (Sprint 3)
-- =============================================================================

-- -----------------------------------------------------------------------------
-- 3.1 infotime_exame_custo
--     Custo padrão por tipo de exame por competência
--     Sprint 3 — Margem por convênio e custo real por exame
-- -----------------------------------------------------------------------------
CREATE TABLE public.infotime_exame_custo (
    id_exame_custo           int8 GENERATED BY DEFAULT AS IDENTITY
                               (INCREMENT BY 1 MINVALUE 1 MAXVALUE 9223372036854775807
                                START 1 CACHE 1 NO CYCLE) NOT NULL,
    id_tenacidade            int8          NOT NULL,
    id_usuario_auditoria     int8          DEFAULT NULL,
    codigo_exame             varchar(50)   NOT NULL,
    descricao_exame          varchar(200)  NOT NULL,
    custo_reagente           numeric(10,4) NOT NULL DEFAULT 0,
    custo_material           numeric(10,4) NOT NULL DEFAULT 0,
    custo_mao_obra           numeric(10,4) NOT NULL DEFAULT 0,
    custo_total              numeric(10,4) GENERATED ALWAYS AS
                               (custo_reagente + custo_material + custo_mao_obra) STORED,
    competencia_inicio        date          NOT NULL,
    competencia_fim           date          DEFAULT NULL, -- NULL = vigente
    data_atualizacao         timestamptz   NOT NULL DEFAULT NOW(),
    endereco_ip_auditoria    varchar(50)   DEFAULT NULL,
    nome_aplicacao_auditoria varchar(255)  DEFAULT NULL,

    CONSTRAINT exame_custo_pkey
        PRIMARY KEY (id_exame_custo),
    CONSTRAINT fk_infotime_exame_custo_id_tenacidade
        FOREIGN KEY (id_tenacidade)
        REFERENCES public.infotime_tenacidade (id_tenacidade)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_exame_custo_id_usuario_auditoria
        FOREIGN KEY (id_usuario_auditoria)
        REFERENCES public.infotime_usuario (id_usuario)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT chk_infotime_exame_custo_custos_positivos
        CHECK (custo_reagente >= 0 AND custo_material >= 0 AND custo_mao_obra >= 0),
    CONSTRAINT chk_infotime_exame_custo_competencia
        CHECK (competencia_fim IS NULL OR competencia_fim > competencia_inicio)
);

CREATE UNIQUE INDEX uq_infotime_exame_custo_01
    ON public.infotime_exame_custo USING btree (id_tenacidade, codigo_exame, competencia_inicio);

CREATE INDEX idx_infotime_exame_custo_id_tenacidade
    ON public.infotime_exame_custo USING btree (id_tenacidade, competencia_inicio DESC);

CREATE INDEX idx_infotime_exame_custo_id_usuario_auditoria
    ON public.infotime_exame_custo USING btree (id_usuario_auditoria);


-- =============================================================================
-- SEÇÃO 4 — TIER 2: TABELAS NOVAS (Sprints 4-8)
-- =============================================================================

-- -----------------------------------------------------------------------------
-- 4.1 infotime_cliente_score
--     Cache do score de inadimplência calculado semanalmente
--     Sprint 4
-- -----------------------------------------------------------------------------
CREATE TABLE public.infotime_cliente_score (
    id_cliente_score         int8 GENERATED BY DEFAULT AS IDENTITY
                               (INCREMENT BY 1 MINVALUE 1 MAXVALUE 9223372036854775807
                                START 1 CACHE 1 NO CYCLE) NOT NULL,
    id_tenacidade            int8          NOT NULL,
    id_cliente               int8          NOT NULL,
    id_usuario_auditoria     int8          DEFAULT NULL,
    score                    numeric(5,2)  NOT NULL,
    classificacao            varchar(10)   NOT NULL, -- 'VERDE' | 'AMARELO' | 'VERMELHO'
    dia_medio_atraso         numeric(6,2)  DEFAULT NULL,
    desvio_padrao_atraso     numeric(6,2)  DEFAULT NULL,
    percentual_em_atraso     numeric(5,2)  DEFAULT NULL,
    qtd_lancamentos_6m       int4          DEFAULT NULL,
    qtd_atrasados_6m         int4          DEFAULT NULL,
    maior_atraso_6m          int4          DEFAULT NULL,
    valor_medio_mensal       numeric(15,2) DEFAULT NULL,
    data_calculo             timestamptz   NOT NULL DEFAULT NOW(),
    data_proximo_calculo     timestamptz   DEFAULT NULL,
    endereco_ip_auditoria    varchar(50)   DEFAULT NULL,
    nome_aplicacao_auditoria varchar(255)  DEFAULT NULL,

    CONSTRAINT cliente_score_pkey
        PRIMARY KEY (id_cliente_score),
    CONSTRAINT uq_infotime_cliente_score_01
        UNIQUE (id_tenacidade, id_cliente),
    CONSTRAINT chk_infotime_cliente_score_range
        CHECK (score BETWEEN 0 AND 100),
    CONSTRAINT fk_infotime_cliente_score_id_tenacidade
        FOREIGN KEY (id_tenacidade)
        REFERENCES public.infotime_tenacidade (id_tenacidade)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_cliente_score_id_cliente
        FOREIGN KEY (id_cliente)
        REFERENCES public.infotime_cliente (id_cliente)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_cliente_score_id_usuario_auditoria
        FOREIGN KEY (id_usuario_auditoria)
        REFERENCES public.infotime_usuario (id_usuario)
        ON DELETE RESTRICT ON UPDATE RESTRICT
);

CREATE INDEX idx_infotime_cliente_score_id_tenacidade
    ON public.infotime_cliente_score USING btree (id_tenacidade);

CREATE INDEX idx_infotime_cliente_score_id_cliente
    ON public.infotime_cliente_score USING btree (id_tenacidade, id_cliente);

CREATE INDEX idx_infotime_cliente_score_classificacao
    ON public.infotime_cliente_score USING btree (id_tenacidade, classificacao, score);

CREATE INDEX idx_infotime_cliente_score_id_usuario_auditoria
    ON public.infotime_cliente_score USING btree (id_usuario_auditoria);

-- -----------------------------------------------------------------------------
-- 4.2 infotime_extrato_bancario_lote
--     Cabeçalho de cada importação de extrato OFX/CSV
--     Sprint 5 — Conciliação bancária
-- -----------------------------------------------------------------------------
CREATE TABLE public.infotime_extrato_bancario_lote (
    id_extrato_bancario_lote int8 GENERATED BY DEFAULT AS IDENTITY
                               (INCREMENT BY 1 MINVALUE 1 MAXVALUE 9223372036854775807
                                START 1 CACHE 1 NO CYCLE) NOT NULL,
    id_tenacidade            int8          NOT NULL,
    id_conta_caixa           int8          NOT NULL,
    id_usuario_auditoria     int8          DEFAULT NULL,
    data_importacao          timestamptz   NOT NULL DEFAULT NOW(),
    nome_arquivo             varchar(255)  DEFAULT NULL,
    formato_arquivo          varchar(10)   NOT NULL, -- 'OFX' | 'OFXV2' | 'CSV'
    data_inicio_periodo      date          NOT NULL,
    data_fim_periodo         date          NOT NULL,
    total_creditos           numeric(15,2) DEFAULT NULL,
    total_debitos            numeric(15,2) DEFAULT NULL,
    qtd_movimentos           int4          DEFAULT NULL,
    qtd_conciliados_auto     int4          NOT NULL DEFAULT 0,
    qtd_conciliados_manual   int4          NOT NULL DEFAULT 0,
    qtd_pendentes            int4          NOT NULL DEFAULT 0,
    endereco_ip_auditoria    varchar(50)   DEFAULT NULL,
    nome_aplicacao_auditoria varchar(255)  DEFAULT NULL,

    CONSTRAINT extrato_bancario_lote_pkey
        PRIMARY KEY (id_extrato_bancario_lote),
    CONSTRAINT chk_infotime_extrato_bancario_lote_periodo
        CHECK (data_fim_periodo >= data_inicio_periodo),
    CONSTRAINT fk_infotime_extrato_bancario_lote_id_tenacidade
        FOREIGN KEY (id_tenacidade)
        REFERENCES public.infotime_tenacidade (id_tenacidade)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_extrato_bancario_lote_id_conta_caixa
        FOREIGN KEY (id_conta_caixa)
        REFERENCES public.infotime_conta_caixa (id_conta_caixa)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_extrato_bancario_lote_id_usuario_auditoria
        FOREIGN KEY (id_usuario_auditoria)
        REFERENCES public.infotime_usuario (id_usuario)
        ON DELETE RESTRICT ON UPDATE RESTRICT
);

CREATE INDEX idx_infotime_extrato_bancario_lote_id_tenacidade
    ON public.infotime_extrato_bancario_lote USING btree (id_tenacidade);

CREATE INDEX idx_infotime_extrato_bancario_lote_id_conta_caixa
    ON public.infotime_extrato_bancario_lote USING btree (id_conta_caixa);

CREATE INDEX idx_infotime_extrato_bancario_lote_data_importacao
    ON public.infotime_extrato_bancario_lote USING btree (data_importacao DESC);

CREATE INDEX idx_infotime_extrato_bancario_lote_id_usuario_auditoria
    ON public.infotime_extrato_bancario_lote USING btree (id_usuario_auditoria);

-- -----------------------------------------------------------------------------
-- 4.3 infotime_extrato_bancario_linha
--     Cada movimento individual do extrato bancário importado
--     Sprint 5 — Conciliação bancária
-- -----------------------------------------------------------------------------
CREATE TABLE public.infotime_extrato_bancario_linha (
    id_extrato_bancario_linha int8 GENERATED BY DEFAULT AS IDENTITY
                                (INCREMENT BY 1 MINVALUE 1 MAXVALUE 9223372036854775807
                                 START 1 CACHE 1 NO CYCLE) NOT NULL,
    id_extrato_bancario_lote  int8          NOT NULL,
    id_tenacidade             int8          DEFAULT NULL,
    id_usuario_auditoria      int8          DEFAULT NULL,
    data_movimento            date          NOT NULL,
    valor                     numeric(15,2) NOT NULL, -- positivo=crédito, negativo=débito
    tipo                      varchar(10)   NOT NULL, -- 'CREDITO' | 'DEBITO'
    historico_banco           varchar(500)  DEFAULT NULL,
    numero_documento_banco    varchar(100)  DEFAULT NULL,
    cnpj_contraparte          varchar(18)   DEFAULT NULL,
    status_conciliacao        varchar(25)   NOT NULL DEFAULT 'PENDENTE',
                                            -- 'PENDENTE' | 'CONCILIADO_AUTO'
                                            -- | 'CONCILIADO_MANUAL' | 'IGNORADO'
    id_lancamento_receita     int8          DEFAULT NULL,
    id_lancamento_despesa     int8          DEFAULT NULL,
    confianca_match           numeric(5,2)  DEFAULT NULL, -- 0–100%
    data_conciliacao          timestamptz   DEFAULT NULL,
    observacao                varchar(500)  DEFAULT NULL,
    endereco_ip_auditoria     varchar(50)   DEFAULT NULL,
    nome_aplicacao_auditoria  varchar(255)  DEFAULT NULL,

    CONSTRAINT extrato_bancario_linha_pkey
        PRIMARY KEY (id_extrato_bancario_linha),
    CONSTRAINT fk_infotime_extrato_bancario_linha_id_lote
        FOREIGN KEY (id_extrato_bancario_lote)
        REFERENCES public.infotime_extrato_bancario_lote (id_extrato_bancario_lote)
        ON DELETE CASCADE ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_extrato_bancario_linha_id_lancamento_receita
        FOREIGN KEY (id_lancamento_receita)
        REFERENCES public.infotime_lancamento_receita (id_lancamento_receita)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_extrato_bancario_linha_id_lancamento_despesa
        FOREIGN KEY (id_lancamento_despesa)
        REFERENCES public.infotime_lancamento_despesa (id_lancamento_despesa)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_extrato_bancario_linha_id_usuario_auditoria
        FOREIGN KEY (id_usuario_auditoria)
        REFERENCES public.infotime_usuario (id_usuario)
        ON DELETE RESTRICT ON UPDATE RESTRICT
);

CREATE INDEX idx_infotime_extrato_bancario_linha_id_lote
    ON public.infotime_extrato_bancario_linha USING btree (id_extrato_bancario_lote);

CREATE INDEX idx_infotime_extrato_bancario_linha_status
    ON public.infotime_extrato_bancario_linha USING btree (status_conciliacao);

CREATE INDEX idx_infotime_extrato_bancario_linha_data
    ON public.infotime_extrato_bancario_linha USING btree (data_movimento);

CREATE INDEX idx_infotime_extrato_bancario_linha_valor
