-- -----------------------------------------------------------------------------
-- 4.4 infotime_pix_configuracao
--     Credenciais PIX por conta caixa (armazenar client_secret criptografado)
--     Sprint 6 — PIX integrado
-- -----------------------------------------------------------------------------
CREATE TABLE public.infotime_pix_configuracao (
    id_pix_configuracao      int8 GENERATED BY DEFAULT AS IDENTITY
                               (INCREMENT BY 1 MINVALUE 1 MAXVALUE 9223372036854775807
                                START 1 CACHE 1 NO CYCLE) NOT NULL,
    id_tenacidade            int8         NOT NULL,
    id_conta_caixa           int8         NOT NULL,
    id_usuario_auditoria     int8         DEFAULT NULL,
    ambiente                 varchar(10)  NOT NULL, -- 'PRODUCAO' | 'SANDBOX'
    client_id                varchar(255) NOT NULL,
    client_secret            text         NOT NULL, -- armazenar criptografado AES-256
    chave_pix                varchar(100) NOT NULL, -- EVP, CNPJ, e-mail ou telefone
    banco                    varchar(50)  NOT NULL, -- 'INTER' | 'SICOOB' | 'ITAU' | 'BB'
    certificado_pem          text         DEFAULT NULL, -- mTLS para Inter/Sicoob
    ativo                    bpchar(1)    NOT NULL DEFAULT 'S',
    data_cadastro            timestamptz  NOT NULL DEFAULT NOW(),
    endereco_ip_auditoria    varchar(50)  DEFAULT NULL,
    nome_aplicacao_auditoria varchar(255) DEFAULT NULL,

    CONSTRAINT pix_configuracao_pkey
        PRIMARY KEY (id_pix_configuracao),
    CONSTRAINT uq_infotime_pix_configuracao_01
        UNIQUE (id_conta_caixa),
    CONSTRAINT fk_infotime_pix_configuracao_id_tenacidade
        FOREIGN KEY (id_tenacidade)
        REFERENCES public.infotime_tenacidade (id_tenacidade)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_pix_configuracao_id_conta_caixa
        FOREIGN KEY (id_conta_caixa)
        REFERENCES public.infotime_conta_caixa (id_conta_caixa)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_pix_configuracao_id_usuario_auditoria
        FOREIGN KEY (id_usuario_auditoria)
        REFERENCES public.infotime_usuario (id_usuario)
        ON DELETE RESTRICT ON UPDATE RESTRICT
);

CREATE INDEX idx_infotime_pix_configuracao_id_tenacidade
    ON public.infotime_pix_configuracao USING btree (id_tenacidade);

CREATE INDEX idx_infotime_pix_configuracao_id_conta_caixa
    ON public.infotime_pix_configuracao USING btree (id_conta_caixa);

CREATE INDEX idx_infotime_pix_configuracao_id_usuario_auditoria
    ON public.infotime_pix_configuracao USING btree (id_usuario_auditoria);

-- -----------------------------------------------------------------------------
-- 4.5 infotime_pix_cobranca
--     Cobranças PIX geradas e rastreamento de pagamentos via webhook
--     Sprint 6 — PIX integrado
-- -----------------------------------------------------------------------------
CREATE TABLE public.infotime_pix_cobranca (
    id_pix_cobranca          int8 GENERATED BY DEFAULT AS IDENTITY
                               (INCREMENT BY 1 MINVALUE 1 MAXVALUE 9223372036854775807
                                START 1 CACHE 1 NO CYCLE) NOT NULL,
    id_tenacidade            int8          NOT NULL,
    id_lancamento_receita    int8          DEFAULT NULL,
    id_usuario_auditoria     int8          DEFAULT NULL,
    tx_id                    varchar(35)   NOT NULL,  -- identificador único PIX (BACEN)
    e2e_id                   varchar(32)   DEFAULT NULL, -- preenchido no pagamento
    valor                    numeric(15,2) NOT NULL,
    status                   varchar(40)   NOT NULL DEFAULT 'ATIVA',
                                           -- 'ATIVA' | 'CONCLUIDA'
                                           -- | 'REMOVIDA_PELO_USUARIO_RECEBEDOR'
                                           -- | 'REMOVIDA_PELO_PSP'
    qr_code                  text          DEFAULT NULL, -- payload EMV
    imagem_qr_code           text          DEFAULT NULL, -- PNG base64
    data_criacao             timestamptz   NOT NULL DEFAULT NOW(),
    data_vencimento          date          DEFAULT NULL,
    data_pagamento           timestamptz   DEFAULT NULL,
    valor_pago               numeric(15,2) DEFAULT NULL,
    cnpj_pagador             varchar(18)   DEFAULT NULL,
    nome_pagador             varchar(200)  DEFAULT NULL,
    info_pagador             text          DEFAULT NULL,
    webhook_payload          jsonb         DEFAULT NULL, -- payload bruto para auditoria
    tentativas_consulta      int4          NOT NULL DEFAULT 0,
    endereco_ip_auditoria    varchar(50)   DEFAULT NULL,
    nome_aplicacao_auditoria varchar(255)  DEFAULT NULL,

    CONSTRAINT pix_cobranca_pkey
        PRIMARY KEY (id_pix_cobranca),
    CONSTRAINT uq_infotime_pix_cobranca_tx_id
        UNIQUE (tx_id),
    CONSTRAINT fk_infotime_pix_cobranca_id_tenacidade
        FOREIGN KEY (id_tenacidade)
        REFERENCES public.infotime_tenacidade (id_tenacidade)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_pix_cobranca_id_lancamento_receita
        FOREIGN KEY (id_lancamento_receita)
        REFERENCES public.infotime_lancamento_receita (id_lancamento_receita)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_pix_cobranca_id_usuario_auditoria
        FOREIGN KEY (id_usuario_auditoria)
        REFERENCES public.infotime_usuario (id_usuario)
        ON DELETE RESTRICT ON UPDATE RESTRICT
);

CREATE UNIQUE INDEX idx_infotime_pix_cobranca_tx_id
    ON public.infotime_pix_cobranca USING btree (tx_id);

CREATE INDEX idx_infotime_pix_cobranca_status
    ON public.infotime_pix_cobranca USING btree (status);

CREATE INDEX idx_infotime_pix_cobranca_id_lancamento_receita
    ON public.infotime_pix_cobranca USING btree (id_lancamento_receita)
    WHERE id_lancamento_receita IS NOT NULL;

CREATE INDEX idx_infotime_pix_cobranca_id_tenacidade
    ON public.infotime_pix_cobranca USING btree (id_tenacidade, data_criacao DESC);

CREATE INDEX idx_infotime_pix_cobranca_id_usuario_auditoria
    ON public.infotime_pix_cobranca USING btree (id_usuario_auditoria);

