    nome_contato             varchar(200) DEFAULT NULL,
    ativo                    bpchar(1)    NOT NULL DEFAULT 'S',
    data_cadastro            timestamptz  NOT NULL DEFAULT NOW(),
    ultimo_acesso            timestamptz  DEFAULT NULL,
    token_reset_senha        varchar(100) DEFAULT NULL,
