    tentativas_login         int4         NOT NULL DEFAULT 0,
    bloqueado_ate            timestamptz  DEFAULT NULL,
    endereco_ip_auditoria    varchar(50)  DEFAULT NULL,
    nome_aplicacao_auditoria varchar(255) DEFAULT NULL,

    CONSTRAINT portal_usuario_pkey
