-- -----------------------------------------------------------------------------
CREATE TABLE public.infotime_portal_acesso_log (
    id_portal_acesso_log     int8 GENERATED BY DEFAULT AS IDENTITY
                               (INCREMENT BY 1 MINVALUE 1 MAXVALUE 9223372036854775807
                                START 1 CACHE 1 NO CYCLE) NOT NULL,
