                                          -- 'LOGIN' | 'LOGOUT' | 'VER_FATURA'
                                          -- | 'GERAR_PIX' | 'BAIXAR_NF'
                                          -- | 'VER_HISTORICO' | 'RESET_SENHA'
    endereco_ip_auditoria    varchar(50)  DEFAULT NULL,
    nome_aplicacao_auditoria varchar(255) DEFAULT NULL,

    CONSTRAINT portal_acesso_log_pkey
