-- -----------------------------------------------------------------------------
-- 4.8 infotime_conta_saldo
--     Saldos de abertura por plano de conta e competência (base do balanço)
--     Sprint 7 — Balanço patrimonial e DFC
-- -----------------------------------------------------------------------------
CREATE TABLE public.infotime_conta_saldo (
    id_conta_saldo           int8 GENERATED BY DEFAULT AS IDENTITY
                               (INCREMENT BY 1 MINVALUE 1 MAXVALUE 9223372036854775807
                                START 1 CACHE 1 NO CYCLE) NOT NULL,
    id_tenacidade            int8          NOT NULL,
    id_plano_conta           int8          NOT NULL,
    id_usuario_auditoria     int8          DEFAULT NULL,
    competencia              date          NOT NULL, -- sempre primeiro dia do mês
    saldo_inicial            numeric(15,2) NOT NULL DEFAULT 0,
    saldo_final              numeric(15,2) DEFAULT NULL, -- calculado no fechamento
    data_fechamento          timestamptz   DEFAULT NULL,
    endereco_ip_auditoria    varchar(50)   DEFAULT NULL,
    nome_aplicacao_auditoria varchar(255)  DEFAULT NULL,

    CONSTRAINT conta_saldo_pkey
        PRIMARY KEY (id_conta_saldo),
    CONSTRAINT uq_infotime_conta_saldo_01
        UNIQUE (id_tenacidade, id_plano_conta, competencia),
    CONSTRAINT chk_infotime_conta_saldo_dia1
        CHECK (EXTRACT(DAY FROM competencia) = 1),
    CONSTRAINT fk_infotime_conta_saldo_id_tenacidade
        FOREIGN KEY (id_tenacidade)
        REFERENCES public.infotime_tenacidade (id_tenacidade)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_conta_saldo_id_plano_conta
        FOREIGN KEY (id_plano_conta)
        REFERENCES public.infotime_plano_conta (id_plano_conta)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_conta_saldo_id_usuario_auditoria
        FOREIGN KEY (id_usuario_auditoria)
        REFERENCES public.infotime_usuario (id_usuario)
        ON DELETE RESTRICT ON UPDATE RESTRICT
);

CREATE INDEX idx_infotime_conta_saldo_id_tenacidade
    ON public.infotime_conta_saldo USING btree (id_tenacidade, competencia DESC);

CREATE INDEX idx_infotime_conta_saldo_id_plano_conta
    ON public.infotime_conta_saldo USING btree (id_plano_conta);

CREATE INDEX idx_infotime_conta_saldo_id_usuario_auditoria
    ON public.infotime_conta_saldo USING btree (id_usuario_auditoria);

-- -----------------------------------------------------------------------------
-- 4.9 infotime_lancamento_contabil
--     Partidas dobradas — geradas automaticamente a partir de receitas/despesas
--     e manualmente para ajustes patrimoniais
--     Sprint 7 — Balanço patrimonial e DFC
-- -----------------------------------------------------------------------------
CREATE TABLE public.infotime_lancamento_contabil (
    id_lancamento_contabil   int8 GENERATED BY DEFAULT AS IDENTITY
                               (INCREMENT BY 1 MINVALUE 1 MAXVALUE 9223372036854775807
                                START 1 CACHE 1 NO CYCLE) NOT NULL,
    id_tenacidade            int8          NOT NULL,
    id_usuario_auditoria     int8          DEFAULT NULL,
    data_lancamento          date          NOT NULL,
    historico_contabil       varchar(500)  DEFAULT NULL,
    id_documento_origem      int8          DEFAULT NULL,
    tipo_documento_origem    varchar(30)   DEFAULT NULL,
                                           -- 'LANCAMENTO_RECEITA' | 'LANCAMENTO_DESPESA'
                                           -- | 'AJUSTE_MANUAL' | 'ABERTURA'
    id_conta_debito          int8          NOT NULL,
    id_conta_credito         int8          NOT NULL,
    valor                    numeric(15,2) NOT NULL,
    estornado                bpchar(1)     NOT NULL DEFAULT 'N',
    id_lancamento_estorno    int8          DEFAULT NULL,
    data_criacao             timestamptz   NOT NULL DEFAULT NOW(),
    endereco_ip_auditoria    varchar(50)   DEFAULT NULL,
    nome_aplicacao_auditoria varchar(255)  DEFAULT NULL,

    CONSTRAINT lancamento_contabil_pkey
        PRIMARY KEY (id_lancamento_contabil),
    CONSTRAINT chk_infotime_lancamento_contabil_contas_distintas
        CHECK (id_conta_debito <> id_conta_credito),
    CONSTRAINT chk_infotime_lancamento_contabil_valor_positivo
        CHECK (valor > 0),
    CONSTRAINT fk_infotime_lancamento_contabil_id_tenacidade
        FOREIGN KEY (id_tenacidade)
        REFERENCES public.infotime_tenacidade (id_tenacidade)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_lancamento_contabil_id_conta_debito
        FOREIGN KEY (id_conta_debito)
        REFERENCES public.infotime_plano_conta (id_plano_conta)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_lancamento_contabil_id_conta_credito
        FOREIGN KEY (id_conta_credito)
        REFERENCES public.infotime_plano_conta (id_plano_conta)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_lancamento_contabil_id_estorno
        FOREIGN KEY (id_lancamento_estorno)
        REFERENCES public.infotime_lancamento_contabil (id_lancamento_contabil)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_lancamento_contabil_id_usuario_auditoria
        FOREIGN KEY (id_usuario_auditoria)
        REFERENCES public.infotime_usuario (id_usuario)
        ON DELETE RESTRICT ON UPDATE RESTRICT
);

CREATE INDEX idx_infotime_lancamento_contabil_data
