    output_tokens               int4          DEFAULT NULL,
    modelo_usado                varchar(60)   NOT NULL DEFAULT 'claude-sonnet-4-20250514',
    custo_usd                   numeric(8,6)  DEFAULT NULL,
    endereco_ip_auditoria       varchar(50)   DEFAULT NULL,
    nome_aplicacao_auditoria    varchar(255)  DEFAULT NULL,

    CONSTRAINT previsao_caixa_ia_pkey
