-- 5.3 infotime_alerta_financeiro
--     Alertas automáticos de anomalias detectadas nos lançamentos
--     Sprint 9 — Detecção de anomalias financeiras
-- -----------------------------------------------------------------------------
CREATE TABLE public.infotime_alerta_financeiro (
    id_alerta_financeiro     int8 GENERATED BY DEFAULT AS IDENTITY
                               (INCREMENT BY 1 MINVALUE 1 MAXVALUE 9223372036854775807
                                START 1 CACHE 1 NO CYCLE) NOT NULL,
    id_tenacidade            int8          NOT NULL,
    id_usuario_auditoria     int8          DEFAULT NULL,
    tipo_alerta              varchar(60)   NOT NULL,
                                           -- 'VALOR_ANOMALO_FORNECEDOR'
                                           -- | 'PAGAMENTO_DUPLICADO_SUSPEITO'
                                           -- | 'FORNECEDOR_NOVO_ALTO_VALOR'
                                           -- | 'VALOR_RECEBIDO_DIVERGENTE'
                                           -- | 'LANCAMENTO_HORARIO_SUSPEITO'
    severidade               varchar(10)   NOT NULL,  -- 'BAIXA' | 'MEDIA' | 'ALTA'
    descricao                text          NOT NULL,
    id_lancamento_receita    int8          DEFAULT NULL,
    id_lancamento_despesa    int8          DEFAULT NULL,
    valor_envolvido          numeric(15,2) DEFAULT NULL,
    valor_referencia         numeric(15,2) DEFAULT NULL,
    desvio_percentual        numeric(8,2)  DEFAULT NULL,
    status                   varchar(25)   NOT NULL DEFAULT 'ABERTO',
                                           -- 'ABERTO' | 'INVESTIGANDO'
                                           -- | 'FALSO_POSITIVO' | 'CONFIRMADO' | 'RESOLVIDO'
    data_deteccao            timestamptz   NOT NULL DEFAULT NOW(),
    data_resolucao           timestamptz   DEFAULT NULL,
    id_usuario_responsavel   int8          DEFAULT NULL,
    observacoes              text          DEFAULT NULL,
    endereco_ip_auditoria    varchar(50)   DEFAULT NULL,
    nome_aplicacao_auditoria varchar(255)  DEFAULT NULL,

    CONSTRAINT alerta_financeiro_pkey
        PRIMARY KEY (id_alerta_financeiro),
    CONSTRAINT fk_infotime_alerta_financeiro_id_tenacidade
        FOREIGN KEY (id_tenacidade)
        REFERENCES public.infotime_tenacidade (id_tenacidade)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_alerta_financeiro_id_lancamento_receita
        FOREIGN KEY (id_lancamento_receita)
        REFERENCES public.infotime_lancamento_receita (id_lancamento_receita)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_alerta_financeiro_id_lancamento_despesa
        FOREIGN KEY (id_lancamento_despesa)
        REFERENCES public.infotime_lancamento_despesa (id_lancamento_despesa)
        ON DELETE RESTRICT ON UPDATE RESTRICT,
    CONSTRAINT fk_infotime_alerta_financeiro_id_usuario_auditoria
        FOREIGN KEY (id_usuario_auditoria)
        REFERENCES public.infotime_usuario (id_usuario)
        ON DELETE RESTRICT ON UPDATE RESTRICT
);

